INSERT INTO votes VALUES(215,'Hier kannst du den Inhalt deiner Sitzung benennen, beschreiben und bearbeiten.\n\n NEU ANORDNEN\n Um Elemente neu anzuordnen, drücke lange auf ein Element und\n ziehe es an seine neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, schiebe es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippe ihn einfach einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücke die +-Schaltfläche.',1779641246213,18,1,61);
