INSERT INTO votes VALUES(1579,'এখানে আপনি আপনার সেশনের বিষয়বস্তুর নামকরণ, বর্ণনা এবং সম্পাদনা করতে পারেন।\n\n পুনর্বিন্যাস\n আইটেমগুলি পুনর্বিন্যাস করতে, একটি আইটেমে দীর্ঘক্ষণ চাপুন এবং\n এটি তার নতুন অবস্থানে টেনে নিয়ে যান।\n\n মুছে ফেলা\n একটি আইটেম মুছে ফেলতে, এটিকে ডানদিকে সরান।\n\n সম্পাদনা\n একটি বিভাগ সম্পাদনা করতে, এটিতে একবার স্পর্শ করুন।\n\n যোগ করা\n একটি নতুন বিভাগ যোগ করতে, + বোতাম টিপুন।',1779673844064,9,10,61);
