INSERT INTO votes VALUES(4992,'Anseo is féidir leat ainm a thabhairt ar, cur síos a dhéanamh ar, agus inneachar do Sheisiún a chur in eagar.\n\n ATHORDÚ\n Chun na míreanna a athordú, brúigh go fada ar mhír agus\n tarraing í go dtí a háit nua.\n\n SCRIOSTE\n Chun mír a scriosadh, bog í ar dheis.\n\n EAGARTHÓIREACHT\n Chun ranóg a chur in eagar, tapáil í uair amháin.\n\n CUIR LEIS\n Chun ranóg nua a chur leis, brúigh an cnaipe +.',1779683686805,31,10,61);
