INSERT INTO votes VALUES(5146,'An seo ''s urrainn dhut ainm a thoirt air an t-Seisean agad, tuairisgeul a thoirt agus susbaint a dheasachadh.\n\n ATH-SHEÒLACHADH\n Airson nithean ath-sheòlachadh, brùth fada air nì agus\n slaod e gu ionad ùr.\n\n SGUABADH AS\n Airson nì a sguabadh às, gluais e gu deas.\n\n DEASACHADH\n Airson earrann a dheasachadh, thoir suathadh oirre aon turas.\n\n CUR RIS\n Airson earrann ùr a chur ris, brùth am putan +.',1779684000773,32,10,61);
