INSERT INTO votes VALUES(5253,'Zazen Meditaasje Timer — In ienfâldige meditaasje timer mei oanpasbere seksjes, klokklanken en sesjebehear.',1779684581083,30,10,2);
INSERT INTO votes VALUES(5254,'Oarspronklik makke troch Stefan Gaffga. No ûnderholden troch Georg Graf.<br><br>Danke oan Winfried fan <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> foar it besoargjen fan sa''n moaie klokklanken!',1779684581085,30,10,3);
INSERT INTO votes VALUES(5255,'<a href="https://github.com/georgernstgraf/zazentimer/issues">Melde problemen op GitHub</a>',1779684581089,30,10,4);
INSERT INTO votes VALUES(5256,'Dizze applikaasje lit de brûker in set meditaasjesesjes definiearje en jout in timer mei fisuele en hearbere feedback as in diel of de hiele meditaasje dien is.',1779684581093,30,10,5);
INSERT INTO votes VALUES(5259,'Hjir kinne jo jo sesje beneame, beskriuwe en de ynhâld bewurkje.\n\n HERORDERJE\n Om de items te herorderjen, lang yndrukke op in item en\n sleep it nei syn nije posysje.\n\n WISKJE\n Om in item te wiskjen, ferpleats it nei rjochts.\n\n BEWURKJE\n Om in seksje te bewurkjen, tik der ien kear op.\n\n TAHEAKJE\n Om in nije seksje ta te heakjen, druk op de + knop.',1779684581100,30,10,61);
INSERT INTO votes VALUES(5260,'Kin\''t meditaasje net starte: De selektearre sesje hat gjin seksjes.',1779684581103,30,10,79);
INSERT INTO votes VALUES(5261,'Der is gjin sesje dy''t start wurde kin. Meitsje earst ien oan.',1779684581106,30,10,80);
INSERT INTO votes VALUES(5262,'In Zazen Meditaasje rint op it stuit',1779684581108,30,10,81);
INSERT INTO votes VALUES(5263,'Helderens fan it skerm tidens meditaasje',1779684581111,30,10,86);
INSERT INTO votes VALUES(5265,'In backup bewarje fan jo sesjes en lûden op jo SD-kaart.',1779684581115,30,10,88);
INSERT INTO votes VALUES(5272,'Jo sesjes en oanpaste lûden werstelle fan de SD-kaart backup',1779684581135,30,10,95);
INSERT INTO votes VALUES(5274,'Dizze app samlet gjin persoanlike gegevens - it brûkt ek gjin IP-adressen of oare technology-relatearre gegevens, noch samlet, ferwurket of brûkt it se op ienich wize.',1779684581140,30,10,100);
INSERT INTO votes VALUES(5275,'Dit sil al jo sesjes ferfange troch de sesjes yn de backup! (Kin net ûngedien makke wurde!)',1779684581142,30,10,106);
