INSERT INTO votes VALUES(7659,'აქ შეგიძლიათ დაარქვათ სახელი, აღწეროთ და ჩაასწოროთ თქვენი სესიის შემცველობა.\n\n გადალაგება\n ელემენტების გადასალაგებლად, გრძელად დააჭირეთ ელემენტს და\n გადაათრიეთ ახალ პოზიციაზე.\n\n წაშლა\n ელემენტის წასაშლელად, გადაათრიეთ მარჯვნივ.\n\n რედაქტირება\n სექციის რედაქტირებისთვის, უბრალოდ ერთხელ შეეხეთ.\n\n დამატება\n ახალი სექციის დასამატებლად, დააჭირეთ + ღილაკს.',1779688175714,49,10,61);
