INSERT INTO votes VALUES(7813,'Мұнда сессияға атау бере аласыз, сипаттай аласыз және мазмұнын өңдей аласыз.\n\n ТАҒАЙЫНДАУ\n Элементтерді тағайындау үшін, элементті ұзақ басыңыз және\n оны жаңа орнына сүйреңіз.\n\n ЖОЮ\n Элементті жою үшін, оңға жылжытыңыз.\n\n ӨҢДЕУ\n Бөлімді өңдеу үшін, оған бір рет басыңыз.\n\n ҚОСУ\n Жаңа бөлім қосу үшін, + батырмасын басыңыз.',1779688579565,50,10,61);
