INSERT INTO votes VALUES(8063,'ಮೂಲತಃ ಸ್ಟೀಫನ್ ಗಾಫ್ಗಾ ಅವರಿಂದ ರಚಿಸಲ್ಪಟ್ಟಿದೆ. ಪ್ರಸ್ತುತ ಜಾರ್ಜ್ ಗ್ರಾಫ್ ಅವರಿಂದ ನಿರ್ವಹಿಸಲ್ಪಡುತ್ತಿದೆ.<br><br>ಇಷ್ಟು ಅದ್ಭುತವಾದ ಘಂಟೆ ಶಬ್ದಗಳನ್ನು ಒದಗಿಸಿದ <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> ನ ವಿನ್‌ಫ್ರೈಡ್ ಅವರಿಗೆ ಧನ್ಯವಾದಗಳು!',1779689715827,52,10,3);
