INSERT INTO votes VALUES(8121,'ಇಲ್ಲಿ ನಿಮ್ಮ ಸೆಷನ್‌ನ ವಿಷಯಗಳನ್ನು ಹೆಸರಿಸಬಹುದು, ವಿವರಿಸಬಹುದು ಮತ್ತು ಸಂಪಾದಿಸಬಹುದು.\n\n ಮರುಕ್ರಮ\n ಐಟಂಗಳನ್ನು ಮರುಕ್ರಮಗೊಳಿಸಲು, ಒಂದು ಐಟಂ ಅನ್ನು ಉದ್ದವಾಗಿ ಒತ್ತಿ ಮತ್ತು\n ಅದನ್ನು ಹೊಸ ಸ್ಥಾನಕ್ಕೆ ಎಳೆಯಿರಿ.\n\n ಅಳಿಸುವುದು\n ಐಟಂ ಅನ್ನು ಅಳಿಸಲು, ಅದನ್ನು ಬಲಕ್ಕೆ ಸರಿಸಿ.\n\n ಸಂಪಾದನೆ\n ವಿಭಾಗವನ್ನು ಸಂಪಾದಿಸಲು, ಅದನ್ನು ಒಮ್ಮೆ ಸ್ಪರ್ಶಿಸಿ.\n\n ಸೇರಿಸು\n ಹೊಸ ವಿಭಾಗವನ್ನು ಸೇರಿಸಲು, + ಬಟನ್ ಒತ್ತಿ.',1779689715981,52,10,61);
