INSERT INTO votes VALUES(8525,'Bi eslê xwe ji aliyê Stefan Gaffga ve hatiye çêkirin. Niha ji hêla Georg Graf ve tê parastin.<br><br>Spas ji Winfried yê <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> ji bo peydakirina dengên zengilên wisa baş!',1779690448637,55,10,3);
