INSERT INTO votes VALUES(8583,'Li vir hûn dikarin navê, daxuyaniya û naveroka Danişîna xwe biguherînin.\n\n NÛKIRINA RÊZÊ\n Ji bo nûkirina rêzê, pêlê dirêj li ser hêmanekê bikin û\n wê bikişînin cîhê xwe yê nû.\n\n JÊBIRIN\n Ji bo jêbirina hêmanekê, wê biguhezînin rastê.\n\n GUHERANDIN\n Ji bo guherandina beşekê, tenê carekê pêlê bikin.\n\n TÊKIRIN\n Ji bo tevkirina beşeke nû, bişkoja + bitikînin.',1779690448776,55,10,61);
