INSERT INTO votes VALUES(9969,'एतय अहाँ अपन सत्र केर सामग्री केँ नाम दे सकैत छी, वर्णन कए सकैत छी आ संपादित कए सकैत छी।\n\n पुनर्व्यवस्थित करू\n मद केँ पुनर्व्यवस्थित करब लेल, किसी मद पर लामा समय तक दबाउ आ\n ओकरा अपन नवीन स्थान पर खींचू।\n\n मेटाउ\n कोनो मद केँ मेटाबै लेल, ओकरा दाहिना तरफ ल जाउ।\n\n संपादित करू\n कोनो खंड केँ संपादित करब लेल, ओकरा एक बेर छुअ।\n\n जोड़ू\n नवीन खंड जोड़ब लेल, + बटन दबाउ।',1779693022509,64,10,61);
