INSERT INTO votes VALUES(10371,'Zazen Meditation Timer — Famantaranandro fifadiana tsotra azo ovaina ny fizarany, feo lakolosy, ary fitantanana session.',1779702045420,65,10,2);
INSERT INTO votes VALUES(10372,'Noforonin''i Stefan Gaffga tany am-boalohany. Tehirizina ankehitriny i Georg Graf.<br><br>Misaotra an''i Winfried ao amin''ny <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> noho ny fanomezany feo lakolosy tsara toy izany!',1779702045423,65,10,3);
