INSERT INTO votes VALUES(10394,'Eto ianao dia afaka manome anarana, manoritsoritra ary manova ny atin''ny Session-nao.\n\n FANDREMANANA\n Raha te handrindra ny zavatra, tsindrio lava iray ary\n ento any amin''ny toerany vaovao.\n\n FANAFANANA\n Raha te hanafoana zavatra iray, dia afindrao miankavanana.\n\n FANOVANA\n Raha te hanova fizarana iray, dia tsindrio indray mandeha.\n\n FANAMPY\n Raha te hanampy fizarana vaovao, dia tsindrio ny bokotra +.',1779702045486,65,10,61);
INSERT INTO votes VALUES(10395,'Fanoritsoritana ny Session',1779702045489,65,10,64);
INSERT INTO votes VALUES(10396,'Tsy afaka manomboka fifadiana: Tsy misy fizarana ao amin''ny Session nofidiana.',1779702045491,65,10,79);
INSERT INTO votes VALUES(10397,'Tsy misy session azo aanombohana. Azafady mamorona iray aloha.',1779702045494,65,10,80);
