INSERT INTO votes VALUES(10499,'I konei ka taea e koe te whakaingoa, whakaahua me te whakatika i ngā ihirangi o tō Wātū.\n\n WHAKARĀRANGI ANŌ\n Ki te whakarārangi anō i ngā tūemi, pēhi roa i tētahi tūemi ka\n tō ki tōna tūrangawairere.\n\n MUKU\n Ki te muku i tētahi tūemi, neke ki te taha matau.\n\n WHAKATIKA\n Ki te whakatika i tētahi wāhanga, pā noa ki reira.\n\n TĀPIRI\n Ki te tāpiri i tētahi wāhanga hōu, pēhi i te pātene +.',1779702429267,66,10,61);
