INSERT INTO votes VALUES(10653,'Тука можете да именувате, опишете и уредите ги содржините на вашата сесија.\n\n ПРЕУРЕДУВАЊЕ\n За да ги преуредите ставките, притиснете долго на ставката и\n повлечете ја на новата позиција.\n\n БРИШЕЊЕ\n За да избришете ставката, поместете ја надесно.\n\n УРЕДУВАЊЕ\n За да уредите дел, само допрете го еднаш.\n\n ДОДАВАЊЕ\n За да додадете нов дел, притиснете на копчето +.',1779702691675,67,10,61);
