INSERT INTO votes VALUES(11115,'येथे तुम्ही तुमच्या सत्राचे नावकरण, वर्णन आणि सामग्री संपादित करू शकता.\n\n पुनर्क्रमित करणे\n आयटम पुनर्क्रमित करण्यासाठी, एका आयटमवर दीर्घ दाबा आणि\n त्याला त्याच्या नवीन स्थानी ड्रॅग करा.\n\n हटवणे\n आयटम हटवण्यासाठी, त्याला उजवीकडे हलवा.\n\n संपादन\n एक विभाग संपादित करण्यासाठी, फक्त एकदा स्पर्श करा.\n\n जोडणे\n नवीन विभाग जोडण्यासाठी, + बटण दाबा.',1779703869564,70,10,61);
