INSERT INTO votes VALUES(12596,'ਜ਼ਾਜ਼ੇਨ ਧਿਆਨ ਟਾਈਮਰ — ਵਿਉਂਤਯੋਗ ਭਾਗਾਂ, ਘੰਟੀ ਆਵਾਜ਼ਾਂ ਅਤੇ ਸੈਸ਼ਨ ਪ੍ਰਬੰਧਨ ਵਾਲਾ ਇੱਕ ਸਧਾਰਨ ਧਿਆਨ ਟਾਈਮਰ।',1779706735960,81,10,2);
INSERT INTO votes VALUES(12597,'ਸ਼ੁਰੂ ਵਿੱਚ ਸਟੀਫਨ ਗਾਫਕਾ ਦੁਆਰਾ ਬਣਾਇਆ ਗਿਆ। ਵਰਤਮਾਨ ਵਿੱਚ ਜਾਰਜ ਗਰਾਫ ਦੁਆਰਾ ਸੰਭਾਲਿਆ ਜਾ ਰਿਹਾ ਹੈ।<br><br>ਇੰਨੀਆਂ ਸ਼ਾਨਦਾਰ ਘੰਟੀ ਆਵਾਜ਼ਾਂ ਪ੍ਰਦਾਨ ਕਰਨ ਲਈ <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> ਦੇ ਵਿਨਫ੍ਰੀਡ ਦਾ ਧੰਨਵਾਦ!',1779706735962,81,10,3);
