INSERT INTO votes VALUES(12655,'ਇੱਥੇ ਤੁਸੀਂ ਆਪਣੇ ਸੈਸ਼ਨ ਦੀ ਸਮੱਗਰੀ ਦਾ ਨਾਮ ਰੱਖ ਸਕਦੇ ਹੋ, ਵੇਰਵਾ ਦੇ ਸਕਦੇ ਹੋ ਅਤੇ ਸੰਪਾਦਿਤ ਕਰ ਸਕਦੇ ਹੋ।\n\n ਪੁਨਰ ਕ੍ਰਮਬੱਧ\n ਆਈਟਮਾਂ ਨੂੰ ਪੁਨਰ ਕ੍ਰਮਬੱਧ ਕਰਨ ਲਈ, ਕਿਸੇ ਆਈਟਮ ਨੂੰ ਲੰਬੇ ਸਮੇਂ ਤੱਕ ਦਬਾਓ ਅਤੇ\n ਇਸਨੂੰ ਆਪਣੀ ਨਵੀਂ ਸਥਿਤੀ ਵਿੱਚ ਖਿੱਚੋ।\n\n ਮਿਟਾਉਣਾ\n ਕੋਈ ਆਈਟਮ ਮਿਟਾਉਣ ਲਈ, ਇਸਨੂੰ ਸੱਜੇ ਪਾਸੇ ਵੱਲ ਲਿਜਾਓ।\n\n ਸੰਪਾਦਨ\n ਕਿਸੇ ਭਾਗ ਨੂੰ ਸੰਪਾਦਿਤ ਕਰਨ ਲਈ, ਬੱਸ ਇਸਨੂੰ ਇੱਕ ਵਾਰ ਛੂਹੋ।\n\n ਜੋੜਨਾ\n ਨਵਾਂ ਭਾਗ ਜੋੜਨ ਲਈ, + ਬਟਨ ਦਬਾਓ।',1779706736101,81,10,61);
