INSERT INTO votes VALUES(14965,'இங்கே உங்கள் அமர்வின் உள்ளடக்கத்தை பெயரிடலாம், விவரிக்கலாம் மற்றும் திருத்தலாம்.\n\n மறுசீரமைத்தல்\n உருப்படிகளை மறுசீரமைக்க, ஒரு உருப்படியை நீண்ட நேரம் அழுத்தி\n அதன் புதிய இடத்திற்கு இழுக்கவும்.\n\n நீக்குதல்\n ஒரு உருப்படியை நீக்க, அதை வலதுபுறம் நகர்த்தவும்.\n\n திருத்து\n ஒரு பிரிவைத் திருத்த, அதை ஒருமுறை தொடவும்.\n\n சேர்\n புதிய பிரிவைச் சேர்க்க, + பொத்தானை அழுத்தவும்.',1779710150202,105,10,61);
