INSERT INTO votes VALUES(15119,'ఇక్కడ మీరు మీ సెషన్ యొక్క కంటెంట్‌ను పేరు పెట్టవచ్చు, వివరించవచ్చు మరియు సవరించవచ్చు.\n\n పునఃక్రమీకరణ\n అంశాలను పునఃక్రమీకరించడానికి, ఒక అంశంపై ఎక్కువసేపు నొక్కండి మరియు\n దాన్ని కొత్త స్థానానికి డ్రాగ్ చేయండి.\n\n తొలగింపు\n ఒక అంశాన్ని తొలగించడానికి, దాన్ని కుడివైపుకు తరలించండి.\n\n సవరణ\n ఒక విభాగాన్ని సవరించడానికి, దానిపై ఒకసారి తాకండి.\n\n జోడింపు\n కొత్త విభాగాన్ని జోడించడానికి, + బటన్‌ను నొక్కండి.',1779710558947,106,10,61);
