INSERT INTO votes VALUES(16197,'Tại đây bạn có thể đặt tên, mô tả và chỉnh sửa nội dung Phiên của mình.\n\n SẮP XẾP LẠI\n Để sắp xếp lại các mục, nhấn giữ vào một mục và\n kéo nó đến vị trí mới.\n\n XÓA\n Để xóa một mục, kéo nó sang phải.\n\n CHỈNH SỬA\n Để chỉnh sửa một phần, chỉ cần chạm vào nó một lần.\n\n THÊM\n Để thêm phần mới, nhấn nút +.',1779711954762,117,10,61);
