INSERT INTO votes VALUES(17121,'Тук можете да именувате, описвате и редактирате съдържанието на вашата сесия.\n\n ПРЕНАРЕЖДАНЕ\n За да пренаредите елементите, натиснете продължително върху елемент и\n го плъзнете до новата му позиция.\n\n ИЗТРИВАНЕ\n За да изтриете елемент, преместете го надясно.\n\n РЕДАКТИРАНЕ\n За да редактирате секция, просто я докоснете веднъж.\n\n ДОБАВЯНЕ\n За да добавите нова секция, натиснете бутона +.',1779728946945,7,6,61);
