INSERT INTO votes VALUES(19354,'Hér geturðu nefnt, lýst og breytt innihaldi lotunnar þinnar.\n\n ENDURRÖÐUN\n Til að endurraða atriðum, haltu inni á atriði og\n dragðu það á nýjan stað.\n\n EYÐING\n Til að eyða atriði, færðu það til hægri.\n\n BREYTING\n Til að breyta hluta, snertu hann einu sinni.\n\n BÆTA VIÐ\n Til að bæta við nýjum hluta, ýttu á + hnappinn.',1779732068301,45,6,61);
