INSERT INTO votes VALUES(21510,'Tu môžete pomenovať, popísať a upraviť obsah svojho sedenia.\n\n ZORADENIE\n Ak chcete položky preusporiadať, dlho stlačte položku a\n presuňte ju na novú pozíciu.\n\n VYMAZANIE\n Ak chcete položku odstrániť, posuňte ju doprava.\n\n ÚPRAVA\n Ak chcete sekciu upraviť, stačí sa jej raz dotknúť.\n\n PRIDAŤ\n Ak chcete pridať novú sekciu, stlačte tlačidlo +.',1779734921365,95,6,61);
