INSERT INTO votes VALUES(21972,'Här kan du namnge, beskriva och redigera innehållet i din session.\n\n OMBESTÄLLNING\n För att ändra ordningen, tryck länge på ett objekt och\n dra det till dess nya position.\n\n RADERING\n För att ta bort ett objekt, svep det åt höger.\n\n REDIGERA\n För att redigera en sektion, tryck bara på den en gång.\n\n LÄGG TILL\n För att lägga till en ny sektion, tryck på +-knappen.',1779735573722,103,6,61);
