INSERT INTO votes VALUES(22067,'Zazen தியான நேரங்காட்டி — தனிப்பயனாக்கக்கூடிய பகுதிகள், மணி ஒலிகள் மற்றும் அமர்வு மேலாண்மையுடன் கூடிய எளிய தியான நேரங்காட்டி.',1779735767392,105,6,2);
INSERT INTO votes VALUES(22068,'முதலில் Stefan Gaffga ஆல் உருவாக்கப்பட்டது. தற்போது Georg Graf ஆல் பராமரிக்கப்படுகிறது.<br><br>இவ்வளவு சிறந்த மணி ஒலிகளை வழங்கிய <a href="http://www.meditationsuhren.de">http://www.meditationsuhren.de</a> இன் Winfried அவர்களுக்கு நன்றி!',1779735767394,105,6,3);
