INSERT INTO votes VALUES(22070,'இந்தப் பயன்பாடு பயனர் தியான அமர்வுகளின் தொகுப்பை வரையறுக்க அனுமதிக்கிறது மற்றும் தியானத்தின் ஒரு பகுதி அல்லது முழுத் தியானமும் முடிந்ததும் காட்சி மற்றும் ஒலி அறிவிப்புகளை வழங்கும் நேரங்காட்டியை வழங்குகிறது.',1779735767400,105,6,5);
