INSERT INTO votes VALUES(23809,'এখানে আপনি আপনার সেশনের নাম, বিবরণ এবং বিষয়বস্তু সম্পাদনা করতে পারেন।\n\n পুনর্বিন্যাস\n আইটেম পুনর্বিন্যাস করতে, একটি আইটেমে দীর্ঘক্ষণ চাপুন এবং\n এটিকে তার নতুন অবস্থানে টেনে নিয়ে যান।\n\n মুছে ফেলা\n একটি আইটেম মুছতে, এটিকে ডানদিকে সরান।\n\n সম্পাদনা\n একটি বিভাগ সম্পাদনা করতে, একবার স্পর্শ করুন।\n\n যোগ\n একটি নতুন বিভাগ যোগ করতে, + বোতাম টিপুন।',1779750682912,9,9,61);
