INSERT INTO votes VALUES(24513,'Hier können Sie Ihre Sitzung benennen, beschreiben und deren Inhalt bearbeiten.\n\n SORTIEREN\n Zum Sortieren der Einträge lange auf einen Eintrag drücken und\n an die neue Position ziehen.\n\n LÖSCHEN\n Zum Löschen eines Eintrags nach rechts wischen.\n\n BEARBEITEN\n Zum Bearbeiten eines Abschnitts einmal darauf tippen.\n\n HINZUFÜGEN\n Zum Hinzufügen eines neuen Abschnitts die + Taste drücken.',1779754174557,18,9,61);
INSERT INTO votes VALUES(24514,'Meditation kann nicht gestartet werden: Die ausgewählte Sitzung enthält keine Abschnitte.',1779754174561,18,9,79);
