INSERT INTO votes VALUES(24579,replace('Εδώ μπορείτε να ονομάσετε, περιγράψετε και επεξεργαστείτε τα περιεχόμενα της Συνεδρίας σας.\n\n ΑΝΑΔΙΑΤΑΞΗ\n Για να αναδιατάξετε τα στοιχεία, πατήστε παρατεταμένα σε ένα στοιχείο και\n σύρετέ το στη νέα του θέση.\n\n ΔΙΑΓΡΑΦΗ\n Για να διαγράψετε ένα στοιχείο, σύρετέ το προς τα δεξιά.\n\n ΕΠΕΞΕΡΓΑΣΙΑ\n Για να επεξεργαστείτε μια ενότητα, απλώς αγγίξτε την μία φορά.\n\n ΠΡΟΣΘΗΚΗ\n Για να προσθέσετε μια νέα ενότητα, πατήστε το κουμπί +.','\n',char(10)),1779755106237,21,9,61);
