INSERT INTO votes VALUES(25189,'Ici, vous pouvez nommer, décrire et modifier le contenu de votre session.\n\n RÉORGANISATION\n Pour réorganiser les éléments, appuyez longuement sur un élément et\n faites-le glisser vers sa nouvelle position.\n\n SUPPRESSION\n Pour supprimer un élément, faites-le glisser vers la droite.\n\n ÉDITION\n Pour modifier une section, appuyez simplement une fois dessus.\n\n AJOUT\n Pour ajouter une nouvelle section, appuyez sur le bouton +.',1779779713862,29,9,61);
