INSERT INTO votes VALUES(27143,'Овде можете да го именувате, опишете и уредувате содржината на вашата Сесија.\n\n ПРЕРЕДУВАЊЕ\n За да ги прередите ставките, долго притиснете на ставка и\n влечете ја на нејзината нова позиција.\n\n БРИШЕЊЕ\n За да избришете ставка, поместете ја надесно.\n\n УРЕДУВАЊЕ\n За да уредите дел, само допрете го еднаш.\n\n ДОДАВАЊЕ\n За да додадете нов дел, притиснете го копчето +.',1779796030118,67,9,61);
