INSERT INTO votes VALUES(29952,'Hier können Sie Ihre Sitzung benennen, beschreiben und deren Inhalt bearbeiten.\n\n NEU ANORDNEN\n Um die Elemente neu anzuordnen, tippen Sie lange auf ein Element und\n ziehen Sie es an seine neue Position.\n\n LÖSCHEN\n Um ein Element zu löschen, schieben Sie es nach rechts.\n\n BEARBEITEN\n Um einen Abschnitt zu bearbeiten, tippen Sie ihn einfach einmal an.\n\n HINZUFÜGEN\n Um einen neuen Abschnitt hinzuzufügen, drücken Sie die + Taste.',1779813078394,110,9,61);
