INSERT INTO votes VALUES(30318,'Тут ви можете назвати, описати та редагувати вміст свого сеансу.\n\n ЗМІНА ПОРЯДКУ\n Щоб змінити порядок елементів, довго натисніть на елемент і\n перетягніть його на нове місце.\n\n ВИДАЛЕННЯ\n Щоб видалити елемент, посуньте його вправо.\n\n РЕДАГУВАННЯ\n Щоб редагувати розділ, просто торкніться його один раз.\n\n ДОДАВАННЯ\n Щоб додати новий розділ, натисніть кнопку +.',1779815349745,114,9,61);
